protected static int between(ReadablePartial start, ReadablePartial end, ReadablePeriod zeroInstance) {
    if (start == null || end == null) {
        throw new IllegalArgumentException("ReadablePartial objects must not be null");
    }
    if (start.size() != end.size()) {
        throw new IllegalArgumentException("ReadablePartial objects must have the same set of fields");
    }
    for (int i = 0, isize = start.size(); i < isize; i++) {
        if (start.getFieldType(i) != end.getFieldType(i)) {
            throw new IllegalArgumentException("ReadablePartial objects must have the same set of fields");
        }
    }
    if (DateTimeUtils.isContiguous(start) == false) {
        throw new IllegalArgumentException("ReadablePartial objects must be contiguous");
    }
    if (zeroInstance.size() != 1) {
        throw new IllegalArgumentException("ReadablePeriod must be a single field period");
    }
    Chronology chrono = DateTimeUtils.getChronology(start.getChronology()).withUTC();
    long baseInstant;
    try {
        baseInstant = chrono.getDateTimeMillis(2000, 1, 1, 0, 0, 0, 0);
    } catch (IllegalArgumentException e) {
        baseInstant = 0L;
    }
    int[] values = chrono.get(zeroInstance, chrono.set(start, baseInstant), chrono.set(end, baseInstant));
    return values[0];
}
